def _pct(rng, zone):
    roll = rng.random()
    if zone == "critical":
        if roll < 0.30: return rng.randint(60,100)
        if roll < 0.65: return rng.randint(25,59)
        return rng.randint(0,24)
    if roll < 0.55: return rng.randint(60,100)
    if roll < 0.85: return rng.randint(25,59)
    return rng.randint(0,24)

def _status(p):
    return "green" if p>=60 else "yellow" if p>=25 else "red"

_WATER = [(41.5,29.0,44.0,33.5),(41.5,33.5,44.0,35.0),(43.5,35.5,44.1,36.8),(45.4,34.5,46.5,38.0),(37.0,49.5,47.0,54.5)]
def _ok(a,b):
    for la,lb,ha,hb in _WATER:
        if la<=a<=ha and lb<=b<=hb: return False
    return True
def _coord(rng,lo,hi,glo,ghi):
    for _ in range(30):
        a=round(rng.uniform(lo,hi),6); b=round(rng.uniform(glo,ghi),6)
        if _ok(a,b): return a,b
    return round((lo+hi)/2,6),round((glo+ghi)/2,6)

