def generate_excel_stations():
    rng = random.Random(2024)
    result = []
    for s in EXCEL_STATIONS:
        lat,lng = _coord(rng,s["lat_lo"],s["lat_hi"],s["lng_lo"],s["lng_hi"])
        fuels = list(s["fuels"])
        if "АИ-92" in fuels and "АИ-95" not in fuels: fuels.append("АИ-95")
        fs = [{"fuel_type":f,"availability_pct":_pct(rng,s["zone_type"]),"status":_status(_pct(rng,s["zone_type"]))} for f in fuels]
        result.append({"region":s["region"],"zone_type":s["zone_type"],"name":s["name"],
            "address":s["address"],"lat":lat,"lng":lng,"network":s["network"],
            "queue_cars":rng.randint(0,12),"fuel_statuses":fs})
    return result